const response = $input.all()[0].json;
const fechaReporte = new Date().toISOString().slice(0,10);

try {
  let content = response.choices[0].message.content;
  content = content.replace(/```json/g, '').replace(/```/g, '').trim();

  const firstBracket = content.indexOf('[');
  const lastBracket = content.lastIndexOf(']');

  if (firstBracket !== -1 && lastBracket !== -1) {
      content = content.substring(firstBracket, lastBracket + 1);
  }

  const parsed = JSON.parse(content);

  // Deduplicar por Evento
  const seen = new Set();
  const unique = parsed.filter(item => {
    if (!item.Evento || seen.has(item.Evento)) return false;
    seen.add(item.Evento);
    return true;
  });

  return unique.map(item => ({ json: { ...item, Fecha_Reporte: fechaReporte } }));
} catch (e) {
  const raw = response.choices?.[0]?.message?.content || '';
  const noHayPartidos = raw.includes('NO HAY PARTIDOS') || raw.includes('no hay partidos');
  return [{ json: { 
    Evento: noHayPartidos ? '⚠️ NO HAY PARTIDOS PROGRAMADOS PARA HOY' : 'Error en el análisis',
    Liga_Categoria: '-',
    Analisis_Forma: '-',
    Prediccion_Marcador: '-',
    Mercado_Goles: '-',
    Probabilidad_Victoria: '-',
    Riesgo: '-',
    Justificacion_Clave: '-',
    Fecha_Reporte: fechaReporte
