  }}];
}

return destacadas;

const items = $input.all();

// Si el primer item es nuestro placeholder de "no hay destacadas", lo manejamos
if (items.length === 1 && items[0].json.Evento === 'NO HAY APUESTAS DESTACADAS') {
  const mensaje = 'ℹ️ *REPORTE DE APUESTAS DEL DÍA*\n\n✅ No se encontraron apuestas con probabilidad > 55% hoy.\n\n---\n🤖 Reporte generado automáticamente por IA Deportiva';
  return [{ json: { message: mensaje } }];
}

let mensaje = '🔥 *REPORTE COMPLETO DE APUESTAS - PROBABILIDAD > 55%* 🔥\n\n';
mensaje += `📅 Fecha: ${new Date().toLocaleDateString('es-ES')}\n`;
mensaje += `📊 Total partidos: ${items.length}\n\n`;

// Agrupar por Liga/Categoría
const porLiga = {};
for (const item of items) {
  const d = item.json;
  const liga = d.Liga_Categoria || 'Otros';
  if (!porLiga[liga]) porLiga[liga] = [];
  porLiga[liga].push(d);
}

let contador = 1;
for (const [liga, partidos] of Object.entries(porLiga)) {
  mensaje += `\n🏆 *${liga}*\n`;
  mensaje += '─'.repeat(25) + '\n';
  for (const d of partidos) {
    mensaje += `${contador}. *${d.Evento}*\n`;
    mensaje += `   📈 Prob: ${d.Probabilidad_Victoria} | Riesgo: ${d.Riesgo}\n`;
    mensaje += `   ⚽ Predicción: ${d.Prediccion_Marcador}\n`;
    mensaje += `   🎯 Mercado: ${d.Mercado_Goles || d.Mercado_Puntos || d.Mercado_Carreras || 'N/D'}\n\n`;
    contador++;
  }
}

mensaje += '---\n🤖 Reporte generado automáticamente por IA Deportiva';

return [{ json: { message: mensaje } }];

// Generar Top 3 localmente sin llamar a Groq
const items = $input.all();
const predicciones = items.map(item => item.json);

// Función para extraer probabilidad numérica
const getProb = (p) => {
  if (typeof p.Probabilidad_Victoria === 'string') {
    return parseFloat(p.Probabilidad_Victoria.replace('%', '')) || 0;
  }
  return parseFloat(p.Probabilidad_Victoria) || 0;
};

// Función para mapear riesgo a valor numérico (menor es mejor)
const riesgoValor = (r) => {
  if (r === 'Bajo') return 1;
  if (r === 'Medio') return 2;
  return 3;
};

// Función para determinar deporte a partir de Liga_Categoria
const getDeporte = (liga) => {
  if (!liga) return 'Otro';
  const lower = liga.toLowerCase();
  if (lower.includes('premier') || lower.includes('liga') || lower.includes('ligue') || lower.includes('mls') || lower.includes('champions') || lower.includes('europa') || lower.includes('concacaf') || lower.includes('jupiler')) return 'Fútbol';
  if (lower.includes('nba')) return 'NBA';
  if (lower.includes('mlb')) return 'MLB';
  if (lower.includes('nhl')) return 'NHL';
  if (lower.includes('nfl')) return 'NFL';
  return 'Otro';
};

// Estimar cuota basada en probabilidad (fórmula simple: 1 / (prob/100) * 0.95)
const estimarCuota = (prob) => {
  if (prob >= 80) return '1.50';
  if (prob >= 70) return '1.80';
  if (prob >= 60) return '2.10';
  return '2.50';
};

// Filtrar predicciones con probabilidad > 55%
const filtradas = predicciones.filter(p => {
  const prob = getProb(p);
  return prob > 55;
});

// Ordenar: primero por probabilidad descendente, luego por riesgo (Bajo primero)
filtradas.sort((a, b) => {
  const probDiff = getProb(b) - getProb(a);
  if (probDiff !== 0) return probDiff;
  return riesgoValor(a.Riesgo) - riesgoValor(b.Riesgo);
});

// Tomar las 3 primeras
const top3 = filtradas.slice(0, 3);

// Si no hay suficientes, devolver placeholder
if (top3.length === 0) {
  return [{
    json: {
      Evento: 'No hay suficientes predicciones de calidad',
      Deporte: '-',
      Razon_Clave: 'No se encontraron partidos con probabilidad > 55%',
      Cuota_Sugerida: '-'
    }
  }];
}

// Construir objetos para el recomendador
const recomendaciones = top3.map(p => {
  const prob = getProb(p);
  return {
    Evento: p.Evento,
